mapper.select:
SELECT 
  FROM tbl_transaction_history
 WHERE portfolio_id = #{portfolioId}
   AND stock_cd = #{stockCd}
 ORDER BY trans_dt DESC, trans_id DESC

mapper.insert:
INSERT INTO tbl_transaction_history (
     portfolio_id
   , stock_cd
   , trans_type
   , trans_dt
   , qty
   , price
   , amount
   , fee
   , tax
   , currency
   , memo
   , reg_dt
) VALUES (
     #{portfolioId}
   , #{stockCd}
   , #{transType}
   , #{transDt}
   , #{qty}
   , #{price}
   , #{qty} * #{price}
   , COALESCE(#{fee}, 0)
   , COALESCE(#{tax}, 0)
   , COALESCE(#{currency}, 'USD')
   , #{memo}
   , NOW()
)

mapper.update:
UPDATE tbl_transaction_history
   SET reg_dt = reg_dt

     , trans_type = #{transType}


     , trans_dt = #{transDt}


     , qty = #{qty}


     , price = #{price}


     , amount = COALESCE(#{qty}, qty) * COALESCE(#{price}, price)


     , fee = #{fee}


     , tax = #{tax}


     , currency = #{currency}


     , memo = #{memo}

 WHERE trans_id = #{transId}
